const payload = $json.body ?? $json;
const headers = $json.headers ?? {};

const expectedSecret = $env.N8N_LITO_SIGNUP_WEBHOOK_SECRET || '';
const receivedSecret = headers['x-lito-signup-secret'] || headers['X-Lito-Signup-Secret'] || '';

if (expectedSecret && receivedSecret !== expectedSecret) {
  throw new Error('Unauthorized webhook request');
}

const clean = (value) => (typeof value === 'string' ? value.trim() : '');
const nombre = clean(payload.nombre);
const email = clean(payload.email).toLowerCase();
const telefono = clean(payload.telefono);
const estacionServicio = clean(payload.estacionServicio);
const funcion = clean(payload.funcion);
const mensaje = clean(payload.mensaje);
const source = clean(payload.source) || 'web-sumate-modal';
const receivedAt = clean(payload.receivedAt) || new Date().toISOString();
const metadata = payload.metadata ?? {};
const userAgent = clean(metadata.userAgent) || 'n/d';
const referer = clean(metadata.referer) || 'n/d';
const forwardedFor = clean(metadata.forwardedFor) || 'n/d';

if (!nombre || !email || !telefono) {
  throw new Error('Missing required fields');
}

if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
  throw new Error('Invalid email');
}

const campaignName = $env.LITO_SIGNUP_CAMPAIGN_NAME || 'Lista Azul y Blanca';
const localReceivedAt = new Date(receivedAt).toLocaleString('es-AR', {
  timeZone: 'America/Argentina/Buenos_Aires',
  dateStyle: 'short',
  timeStyle: 'short',
});
const sheetId = $env.LITO_SIGNUP_SHEET_ID || '';
const sheetUrl = sheetId ? `https://docs.google.com/spreadsheets/d/${sheetId}` : '';

const subscriberSubject = `Gracias por sumarte a ${campaignName}`;
const subscriberHtml = [
  `<p>Hola ${nombre},</p>`,
  `<p>Gracias por sumarte a <strong>${campaignName}</strong>. Recibimos tus datos y el equipo se va a poner en contacto pronto.</p>`,
  '<p>Estos son los datos que nos compartiste:</p>',
  '<ul>',
  `<li><strong>Nombre:</strong> ${nombre}</li>`,
  `<li><strong>Email:</strong> ${email}</li>`,
  `<li><strong>Telefono:</strong> ${telefono}</li>`,
  `<li><strong>Estacion de servicio:</strong> ${estacionServicio || 'No informada'}</li>`,
  `<li><strong>Funcion:</strong> ${funcion || 'No informada'}</li>`,
  '</ul>',
  mensaje ? `<p><strong>Mensaje:</strong> ${mensaje}</p>` : '',
  '<p>Gracias por ser parte.</p>',
].filter(Boolean).join('');

const teamSubject = `Nueva suscripcion Sumate: ${nombre}`;
const teamHtml = [
  '<p>Llego una nueva suscripcion desde el modal Sumate.</p>',
  '<ul>',
  `<li><strong>Nombre:</strong> ${nombre}</li>`,
  `<li><strong>Email:</strong> ${email}</li>`,
  `<li><strong>Telefono:</strong> ${telefono}</li>`,
  `<li><strong>Estacion de servicio:</strong> ${estacionServicio || 'No informada'}</li>`,
  `<li><strong>Funcion:</strong> ${funcion || 'No informada'}</li>`,
  `<li><strong>Origen:</strong> ${source}</li>`,
  `<li><strong>Fecha:</strong> ${localReceivedAt}</li>`,
  `<li><strong>Referer:</strong> ${referer}</li>`,
  `<li><strong>IP:</strong> ${forwardedFor}</li>`,
  '</ul>',
  mensaje ? `<p><strong>Mensaje:</strong><br>${mensaje}</p>` : '<p><strong>Mensaje:</strong> No dejo mensaje.</p>',
  sheetUrl ? `<p>Hoja: <a href="${sheetUrl}">${sheetUrl}</a></p>` : '',
].filter(Boolean).join('');

return [{
  json: {
    nombre,
    email,
    telefono,
    estacion_servicio: estacionServicio,
    funcion,
    mensaje,
    source,
    received_at: receivedAt,
    received_at_local: localReceivedAt,
    referer,
    forwarded_for: forwardedFor,
    user_agent: userAgent,
    subscriberSubject,
    subscriberHtml,
    teamSubject,
    teamHtml,
  },
}];
